const Q_CHEMISTRY_1993=[{"id": "objective>Chemistry>1993>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dissolution of common salt in water is a physical change because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the salt can be obtained by crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the salt can be recovered by the evaporation of water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat is not generated during mixing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the solution will not boil at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dissolution of common salt (sodium chloride) in water is a physical change because the salt can be recovered by the evaporation of water. This process does not alter the chemical structure of the salt; it simply separates the salt ions from each other and disperses them in water. When the water evaporates, the salt can be crystallized back out, demonstrating that no new substances are formed.</div>", "topic": "CHEMICAL AND PHYSICAL CHANGES"}, {"id": "objective>Chemistry>1993>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances is a mixture?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sulphur powder</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bronze</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Distilled water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze is a mixture, specifically an alloy made primarily of copper and tin. Unlike pure substances such as sulphur powder, distilled water, or ethanol, which have uniform and definite compositions, mixtures like bronze consist of two or more components that retain their individual properties.</div>", "topic": "CHEMICAL COMBINATION : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>1993>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of oxygen molecules would be produced from the decomposition of 2.50 moles of potassium trioxochlorate (V)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 2.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.75</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7.50</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The decomposition of potassium trioxochlorate (V) produces oxygen gas according to the balanced chemical equation. The reaction can be represented as: 2 KClO3 → 2 KCl + 3 O2. From 2.50 moles of KClO3, we can calculate the moles of O2 produced using the stoichiometry of the reaction, which shows that 2 moles of KClO3 yield 3 moles of O2. Therefore, 2.50 moles of KClO3 would produce 3.75 moles of O2.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>1993>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A balanced chemical equation obeys the law of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conservation of mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difinite proportions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">multiple proportions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conservation of energy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A balanced chemical equation obeys the law of conservation of mass, which states that mass is neither created nor destroyed in a chemical reaction. This means that the total mass of reactants must equal the total mass of products, ensuring that the number of atoms for each element is conserved throughout the reaction.</div>", "topic": "CHEMICAL COMBINATION : LAWS OF CONSERVATION OF MATTER"}, {"id": "objective>Chemistry>1993>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At 25<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and 1atm, a gas occupies a volume of 1.50dm3. What volume will it occupy at 100<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C and 1atm?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.88 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">6.00 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">18.80 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">60.00dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the new volume of a gas when the temperature changes, we can use Charles's Law, which states that the volume of a gas is directly proportional to its temperature (in Kelvin) at constant pressure. The initial conditions are 25°C (298 K) and 1.50 dm³. The final temperature is 100°C (373 K). Using the formula V1/T1 = V2/T2, we can calculate the new volume (V2) as follows: V2 = V1 * (T2/T1) = 1.50 dm³ * (373 K / 298 K) ≈ 1.88 dm³.</div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>1993>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gaseous mixture of 800g of oxygen and 56.0g of nitrogen has a total pressure of 1.8atm. The partial pressure of oxygen in the mixture is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.8atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.0atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.2atm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.4atm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To find the partial pressure of oxygen in a gaseous mixture, we can use Dalton's Law of Partial Pressures. The partial pressure of a gas in a mixture is given by the formula: P(gas) = (n(gas) / n(total)) * P(total). First, we need to calculate the number of moles of oxygen (O2) and nitrogen (N2). The molar mass of O2 is 32 g/mol, and for N2, it is 28 g/mol. Thus, moles of O2 = 800 g / 32 g/mol = 25 moles, and moles of N2 = 56 g / 28 g/mol = 2 moles. The total moles = 25 + 2 = 27 moles. The partial pressure of O2 = (25 / 27) * 1.8 atm ≈ 1.0 atm. Therefore, the correct option is 1.0 atm.</div>", "topic": "GAS LAW"}, {"id": "objective>Chemistry>1993>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the curves above represents the behaviour of 1 mole of an ideal gas?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Curve III above represents the behaviour of 1 mole of an ideal gas</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1993>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For iodine crystals to sublime on heating, the molecules must acquire energy that is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than the forces odf attraction in the solid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to the forces of attraction in th solid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">necessary to melt the solid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than the forces of attraction in both the solid and the liquid phases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For iodine crystals to sublime, the molecules must acquire energy that is greater than the forces of attraction in both the solid and the liquid phases. Sublimation is the process where a solid turns directly into a gas without passing through the liquid phase. This requires sufficient energy to overcome the intermolecular forces holding the molecules in the solid state.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1993>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element, E, has the electronic configuration 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. The reaction of E with a halogen X can give?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span> only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and EX<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The element E has the electronic configuration 1s² 2s² 2p⁶ 3s² 3p³, indicating it is in group 15 of the periodic table (the nitrogen group). When it reacts with a halogen (group 17), it can form compounds such as EX₃ (where E is the element and X is the halogen) and EX₅, depending on the oxidation state of E. Therefore, the correct option is EX₃ and EX₅.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1993>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two atoms represented as <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">235</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U and <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">238</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">92</span>U are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isomers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allotropes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isotopes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anomers</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two atoms represented as ²³⁵U and ²³⁸U are isotopes. Isotopes are atoms of the same element that have the same number of protons but different numbers of neutrons. In this case, both uranium isotopes have 92 protons but differ in their neutron count (143 for ²³⁵U and 146 for ²³⁸U).</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>1993>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As the difference in electronegativity between bonded atoms increases, polarity of the bond?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains unchanged</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduces to zero</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the difference in electronegativity between bonded atoms increases, the polarity of the bond increases. Electronegativity is a measure of an atom's ability to attract and hold onto electrons. A greater difference in electronegativity means that one atom will attract the shared electrons more strongly, resulting in a more polar bond.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1993>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which group of elements forms hydrides that are pyramidal in structure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">V</div>", "<div style=\"font-family:Cambria;font-size:17px;\">VI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Group V elements, such as nitrogen and phosphorus, form hydrides like ammonia (NH3) and phosphine (PH3), which have a pyramidal structure due to the presence of a lone pair of electrons on the central atom. This lone pair causes the other bonds to be pushed down, creating a pyramidal shape.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>1993>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water has a rather high boiling point despite its low molecular mass because of the presence of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic bonding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic bonding</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water has a high boiling point due to hydrogen bonding, which is a strong intermolecular force that occurs between the hydrogen atom of one water molecule and the oxygen atom of another. This bonding requires more energy (in the form of heat) to break, resulting in a higher boiling point compared to other molecules of similar mass.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1993>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in gas-filled electric lamp because it helps to?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">prevent the reduction of the lamp fillaments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent oxidation of the lamp fillaments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the lamp fillament glow brightly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">keep the atmosphere in the lamp inert</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in gas-filled electric lamps because it is an inert gas. It prevents oxidation of the lamp filaments by creating an inert atmosphere that does not react with the filament material, thus prolonging the life of the lamp.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1993>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The air around a petroleum refinery is most likely to contain?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, CO and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, CO and NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The air around a petroleum refinery is most likely to contain sulfur dioxide (SO2), carbon monoxide (CO), and nitrogen dioxide (NO2) due to the combustion processes and chemical reactions that occur during refining. These compounds are common pollutants associated with such industrial activities.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>1993>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water can be identified by the use of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anhydrous copper (II) tetraoxosulphate (VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anhydrous sodium trioxocarbonate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium heptaoxochromate (VII)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper (II) trioxocaronate (IV)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water can be identified using anhydrous copper(II) sulfate (CuSO4), which turns from white to blue when it absorbs water. This is a classic test for the presence of water, as the color change indicates hydration.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1993>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon whereby sodium trioxocarbonate (IV) decahydrate loses some of its water of crystallization on exposure to the atmosphere is known as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deliquescene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effervescence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescence</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon whereby sodium trioxocarbonate (IV) decahydrate (commonly known as washing soda) loses some of its water of crystallization upon exposure to the atmosphere is known as efflorescence. Efflorescence occurs when a hydrated salt loses water to the environment, resulting in the formation of a dry powder. This is different from deliquescence, which involves a substance absorbing moisture from the air and dissolving in it, and hygroscopy, which refers to the ability of a substance to absorb moisture from the air without dissolving. Effervescence refers to the release of gas bubbles in a liquid, which is not applicable in this context.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1993>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A student prepares 0.5 M solution each of hydrochloric and ethanoic acids and then measured pH. The result would show that the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pH values are equal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCI solution has a higher pH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sum of the values is 14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid solution has a higher pH</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrochloric acid (HCl) is a strong acid, which means it completely dissociates in solution, resulting in a higher concentration of hydrogen ions (H⁺) compared to ethanoic acid (acetic acid, CH₃COOH), which is a weak acid and only partially dissociates. Therefore, the pH of the HCl solution will be lower (more acidic) than that of the ethanoic acid solution. This means that the HCl solution has a higher concentration of H⁺ ions, leading to a lower pH value, not a higher one. Thus, the correct option is that the HCl solution has a higher pH, which is incorrect in terms of pH values; it should be lower. Hence, the correct answer is that the ethanoic acid solution has a higher pH.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1993>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> For which salt in the graph above does the solubility increase most rapidly with rise in temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaCl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">KCl</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For many solids that are dissolved in water or any liquid, the solubility increases with a temperature rise. With an increase in kinetic energy, the solvent molecules effectively break apart the solute molecules that are held together by strong intermolecular attractions, and thereby solubility is increased.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1993>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> +  H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> → NH4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. It may be deduced from the reaction above that?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a redox reaction has occurred</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> acts as an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> acts as an acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water acts as an acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (ammonia) reacts with H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> (hydronium ion) to form NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> (ammonium ion) and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O (water). This reaction can be analyzed in terms of acid-base chemistry. H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> donates a proton (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) to NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>, which accepts the proton to become NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>. Therefore, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> acts as an acid in this reaction. The correct option is that H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> acts as an acid.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1993>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">4.0 g of sodium hydroxide in 250 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of solution contains?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.40 moles per dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.10 moles per dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.04 moles per dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.02 moles per dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the concentration of sodium hydroxide (NaOH) in moles per dm³, we first need to calculate the number of moles present in 4.0 g of NaOH. The molar mass of NaOH is approximately 40 g/mol. Therefore, the number of moles is calculated as follows:  <br/>  <br/> Number of moles = mass (g) / molar mass (g/mol) = 4.0 g / 40 g/mol = 0.1 moles. <br/>  <br/> Next, we convert the volume from cm³ to dm³. Since 1 dm³ = 1000 cm³, 250 cm³ is equal to 0.250 dm³.  <br/>  <br/> Now, we can find the concentration in moles per dm³: <br/> Concentration (mol/dm³) = number of moles / volume (dm³) = 0.1 moles / 0.250 dm³ = 0.40 moles per dm³. <br/>  <br/> Thus, the correct answer is 0.40 moles per dm³, which corresponds to option A.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1993>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of a salt of a metal M, a current of 0.5 A flows from for 32 minutes 10 seconds and deposits 0.325 g of M, What is the charge of the metal ion? <br/> (M = 65, If = 96,500 C per mole of electron)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ampere = (Coulomb) x (Sec) x 1930 secs = 965 coulombs (unit of current) <br/> But quantity of electricity = current x time = (Coulomb)/(Sec) x time <br/> If 0.5 A for 32 mins 10 secs; Quantity of electricity = (0.5 coulomb)/(Sec x 1930) secs <br/> = 965 coulombs <br/> Since 965 coulombs give 0.325 g M <br/> i.e1 coulombs = (0.325)/(965) g <br/> ∴96500 coulombs = (0.30)/(965) x 96500 =32.5 g <br/> ∴(65 g)/(32.5) = 2 <br/>  <br/> inference: it takes 2 Faraday of electricity to deposit 1 mole of M. Therefore, the change on M ion = 2. <br/> </div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1993>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the reactions occurs at the anode during the electrolysis of a very dilute aqueous solution of sodium chloride?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → OH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → CI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → HCl + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Hg Na/Hg amalgram</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the electrolysis of a very dilute aqueous solution of sodium chloride, the reaction that occurs at the anode is the oxidation of chloride ions (Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) to chlorine gas (Cl_2). However, in very dilute solutions, hydroxide ions (OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) can also be oxidized to oxygen gas (O_2). The correct reaction at the anode is: 4OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → O_2 + 2H_2O + 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>. The closest option that represents a reaction occurring at the anode is 'OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → HCl + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>', which indicates the production of oxygen gas, thus making option 3 the correct choice.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1993>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Half-Cell reaction</td><td style=\"border:1px solid black;text-align:center;\"> E<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></td><td style=\"border:1px solid black;text-align:center;\">+0.34V</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></td><td style=\"border:1px solid black;text-align:center;\">-0.44V</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Ba<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Ba<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></td><td style=\"border:1px solid black;text-align:center;\">-2.90V</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></td><td style=\"border:1px solid black;text-align:center;\">-0.76V</td></tr></table></div> <br/> From the data above , it can be deduced that the most powerful reducing agent of the four metals</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ba</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most powerful reducing agent is the one with the most negative standard reduction potential. In the given data, Ba<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> has the most negative reduction potential (-2.90V), making it the strongest reducing agent. </div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1993>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation states of chlorine in HOCL, HCLO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and HCLO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> are respectively?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-1, +5, and +7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1, -5 and 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1, +3 and +4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1, +5 and +7</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the oxidation states of chlorine in HOCl, HClO3, and HClO4, we can analyze each compound: In HOCl, Cl has an oxidation state of +1; in HClO3, Cl has an oxidation state of +5; and in HClO4, Cl has an oxidation state of +7. Therefore, the oxidation states are -1, +5, and +7 respectively, which corresponds to option 1.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1993>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction takes places spontaneously if?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">∆G = O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∆S < O and ∆H > O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∆H < T ∆S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∆G > O</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction occurs spontaneously if the change in Gibbs free energy (∆G) is less than zero (∆G < 0). This indicates that the process can occur without external energy input. The option that states '∆H < T ∆S' is a condition that can lead to a negative ∆G, thus indicating spontaneity under certain conditions. Therefore, option 3 is correct.</div>", "topic": "ENERGY CHANGES : GIBBS FREE ENERGY"}, {"id": "objective>Chemistry>1993>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The standard enthalpies of formation of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> in kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> are -394, -242 and -110 respectively. What is the standard enthalpy change for the reaction  <br/> CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>O → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-42 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+42 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-262 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+262 KJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the standard enthalpy change for the reaction CO(g) + H2O(g) → CO2(g) + H2(g), we use the standard enthalpies of formation: ∆H = [enthalpy of products] - [enthalpy of reactants]. The enthalpy of formation for CO2(g) is -394 kJ/mol, for H2(g) is 0 kJ/mol (as it is a standard state), for CO(g) is -110 kJ/mol, and for H2O(g) is -242 kJ/mol. Thus, ∆H = [-394 + 0] - [-110 - 242] = -394 + 110 + 242 = -42 kJ/mol. Therefore, the correct answer is -42 kJ/mol, which corresponds to option 1.</div>", "topic": "ENERGY CHANGES : GIBB'S FREE ENERGY"}, {"id": "objective>Chemistry>1993>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">10g of a solid is in equilibrium with its own vapour. When 1 g of a small amount of solid is added, the vapour pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remains the same</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases by 1%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases by 99%</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a solid is in equilibrium with its own vapor, adding more solid does not change the vapor pressure. This is because the vapor pressure is a property of the liquid (or solid) phase in equilibrium with its vapor, and is dependent on temperature and the nature of the substance, not the amount of solid present. Therefore, the correct answer is that the vapor pressure remains the same.</div>", "topic": "CHEMICAL EQUILIBRA : DYNAMIC EQUILIBRIUM"}, {"id": "objective>Chemistry>1993>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, curve X represents the energy profile for a homogeneous gaseous reaction. Which of the following conditions would produce curve Y for the same reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Increase in temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in the concentration of a reactant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of a catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in pressure</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Addition of a catalyst lowers the activation energy of the curve X to that of Y.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>1993>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NaCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(I)</span> → HCI<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span>. <br/> In the reaction above, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> behaves as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a strong acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a good solvent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a dehydrating agent</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the reaction NaCl(s) + H2SO4(l) → HCl(g) + NaHSO4(s), sulfuric acid (H2SO4) acts as a dehydrating agent. A dehydrating agent removes water from other substances, and in this case, it helps to produce hydrogen chloride gas from sodium chloride by removing water molecules.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1993>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these gases can be dried with concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HBr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Concentrated sulfuric acid (H2SO4) is a strong dehydrating agent and can effectively dry gases. Among the options, HBr (hydrobromic acid) can be dried using concentrated H2SO4, as it reacts with water to form H2SO4 and HBr gas, thus making it suitable for drying.</div>", "topic": "CHEMICAL COMBINATION : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1993>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these salts will produce its metal, oxygen and nitrogen (IV) oxide on heating?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Silver and trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Calcium trioxonitrate (V)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lithium trioxonitrate (V)</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxonitrate (V) (NaNO3) decomposes upon heating to produce sodium oxide, nitrogen dioxide (NO2), and oxygen. This reaction is characteristic of nitrates, particularly those of alkali metals, which release nitrogen oxides and oxygen when heated.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>1993>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An experiment produces a gaseous mixtures of carbon (IV) oxide and carbon (II) oxide. In order to obtain pure carbon (II) oxide, the gas mixture should be?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">passed over heated copper (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through concentrated tetraoxosulphate (IV) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through sodium hydroxide solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through water</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To obtain pure carbon (II) oxide (CO) from a mixture of carbon (IV) oxide (CO2) and carbon (II) oxide (CO), bubbling the gas mixture through sodium hydroxide solution is effective. Sodium hydroxide reacts with carbon dioxide to form sodium carbonate, thus removing CO2 from the mixture and allowing CO to be collected in pure form.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>1993>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a property of ionic chlorides?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They can be decomposed by heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They react with aqueous AgNO3 to give a white precipiate which is soluble in excess ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They explode when in contact with dry ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They react with concentrated tetraoxosulphate (IV) acid to give white fumes of chlorine gas</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ionic chlorides, such as sodium chloride, can react with aqueous silver nitrate (AgNO3) to form a white precipitate of silver chloride (AgCl), which is soluble in excess ammonia. This is a characteristic reaction of halides with silver nitrate.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HALOGENS"}, {"id": "objective>Chemistry>1993>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When dilute aqueous solutions of lead (II) nitrate and potassium bromide are mixed, a precipitate is observed. The products of this reaction are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + KNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + PbBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">PbBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(aq)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When dilute aqueous solutions of lead (II) nitrate (Pb(NO3)2) and potassium bromide (KBr) are mixed, lead(II) bromide (PbBr2) precipitates out of the solution. The balanced reaction produces PbBr2(s) along with potassium ions (K+) and nitrate ions (NO3-), which remain in solution.</div>", "topic": "METALS AND THEIR COMPOUNDS : LEAD"}, {"id": "objective>Chemistry>1993>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze is an alloy of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silver and copper</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver and gold</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper and nickle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper and tin</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bronze is an alloy primarily made of copper and tin. This combination gives bronze its characteristic properties, such as increased strength and resistance to corrosion compared to pure copper.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>1993>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Copper metal will react with concentrated trioxonitrate(V) acid to give</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + NO + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + NO + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuO + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When copper metal reacts with concentrated nitric acid (trioxonitrate(V) acid), it produces copper(II) nitrate (Cu(NO3)2), nitrogen dioxide (NO2), and water (H2O). The reaction is characterized by the formation of NO2, which is a brown gas.</div>", "topic": "CHEMICAL COMBINATION : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>1993>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The active reducing agent in the blast furnace for the extraction of iron is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(II)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the blast furnace for the extraction of iron, carbon (in the form of coke) acts as the primary reducing agent. It reduces iron(III) oxide (Fe2O3) to iron (Fe) by providing the necessary electrons for the reduction process.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>1993>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>) + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(I)</span>O <br/> Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(s)</span> + 2NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(I)</span>O → 2NaAl(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>. <br/> We can conclude from the equations above that Al2O3(s) is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an acidic oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an amphoteric oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a basic oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a neutral oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Al2O3 (aluminum oxide) is considered an amphoteric oxide because it can react with both acids and bases. In the given reactions, it reacts with sulfuric acid (an acid) to form aluminum sulfate and with sodium hydroxide (a base) to form sodium aluminate. This dual reactivity is characteristic of amphoteric oxides.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1993>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The two functional groups in the above compound are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alcohol and amine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid and amine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aldehyde and acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ketone and amine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two functional groups in the above compound are alkanoic acid (-COOH) and amine (-NH2).</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>1993>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fraction of crude oil used as jet fuel is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">refinery gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">diesel oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gasoline</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jet fuel is primarily derived from kerosene, which is a fraction of crude oil. Kerosene has the appropriate properties for use in jet engines, including a high flash point and good combustion characteristics.</div>", "topic": "HYDROCARBON"}, {"id": "objective>Chemistry>1993>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The IUPAC nomenclature for the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,5 dimethylhexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,1 dimethyl, 3 methylpentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,4 dimethylhexane</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature for the compound above is 2,4 dimethylhexane</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1993>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">It is not desirable to use lead tetraethyl as an anti-knock agent because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is expensive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">of pollution effects from the exhaust fumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it lowers the octane rating of petrol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is explosive</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lead tetraethyl was used as an anti-knock agent in gasoline, but it is not desirable due to the pollution effects from the exhaust fumes. Lead is a toxic substance that can cause serious environmental and health issues, leading to its phased-out use in many countries.</div>", "topic": "HYDROCARBON"}, {"id": "objective>Chemistry>1993>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The carbon atoms on ethane are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> hybridized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sp hybridized</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In ethane (C2H6), the carbon atoms are sp^3 hybridized. This means that each carbon atom forms four sigma bonds with hydrogen atoms, resulting in a tetrahedral geometry around each carbon atom.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1993>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Catalytic hydrogenation of benzene produces?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an aromatic hydrocarbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">margarine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclohexane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">D.D.T</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The catalytic hydrogenation of benzene results in the formation of cyclohexane. This reaction involves the addition of hydrogen (H2) across the double bonds of benzene, converting it into a saturated hydrocarbon, cyclohexane.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1993>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isomers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">esters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carboxylic acids</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymers</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isomers are compounds that have the same molecular formula (same number and types of atoms) but different arrangements of atoms in space or different structural arrangements, leading to different properties.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1993>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Palm wine turns sour with time because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the sugar content is converted into alcohol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the carbon (IV) oxide formed during the fermentation process has a sour taste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is commonly adulterated by the tappers and sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microbial activity results in the production of orgain acids within it</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Palm wine turns sour due to microbial activity, specifically the action of bacteria and yeast that produce organic acids, such as acetic acid, during fermentation. This process leads to a decrease in pH, resulting in a sour taste. The option stating that 'microbial activity results in the production of organic acids within it' accurately describes this phenomenon.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1993>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The function of the copper (ll)tetraoxosulphate (IV) in dilute H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> in the figure above is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorb phosphine impurity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorb ethene impurity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">from an acetylide with ethyne</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the copper (ll)tetraoxosulphate (IV) in dilute H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> in the figure above is to absorb phosphine impurity</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>1993>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following represents saponification?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reaction of carboxylic acids with sodium hydroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reaction of alkanoates with acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reaction of alkanoates with alcohols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reaction of alkanoates with sodium hydroxide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Saponification is the chemical reaction that occurs when an alkali reacts with fats or oils to produce soap and glycerol. Specifically, it involves the reaction of alkanoates (fatty acid salts) with sodium hydroxide (an alkali). Therefore, the option 'Reaction of alkanoates with sodium hydroxide' correctly represents saponification.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>1993>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The confirmatory test for alkanoic acids in organic qualitative analysis is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">turning of wet blue litmus paper red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction with alkanols to form esters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction with sodium hydroxide to form salt and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction with aqueous Na2COsp3 to liberate a gas which turns lime water milky</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The confirmatory test for alkanoic acids (carboxylic acids) in organic qualitative analysis is the ability to turn wet blue litmus paper red. This is due to the acidic nature of alkanoic acids, which donate protons (H+) in solution, thus lowering the pH and causing the blue litmus to change color. Therefore, the option 'turning of wet blue litmus paper red' is the correct answer.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}];
